package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to query SLB information
// and exports the formatted result to a JSON file using jq.
// Parameters:
//   - loadBalancerName: The name of the load balancer to query
//   - outputFile: The path where the output JSON file should be saved
//
// Returns:
//   - string: The combined stdout and stderr output from the command execution
//   - error: Any error encountered during command execution
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if strings.TrimSpace(loadBalancerName) == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if strings.TrimSpace(outputFile) == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command
	aliyunCmd := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)

	// Create the jq command
	jqCmd := exec.Command(
		"jq",
		".LoadBalancers.LoadBalancer[]",
	)

	// Create a pipe to connect aliyun's stdout to jq's stdin
	pipeReader, pipeWriter := io.Pipe()
	aliyunCmd.Stdout = pipeWriter
	jqCmd.Stdin = pipeReader

	// Create buffers to capture output
	var jqOutput bytes.Buffer
	var jqError bytes.Buffer
	jqCmd.Stdout = &jqOutput
	jqCmd.Stderr = &jqError

	// Start the jq command first
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		pipeWriter.Close()
		jqCmd.Process.Kill()
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close the write end of the pipe to signal EOF to jq
	pipeWriter.Close()

	// Wait for jq command to complete
	jqErr := jqCmd.Wait()

	// Combine output from both commands
	var combinedOutput bytes.Buffer
	combinedOutput.WriteString("=== aliyun command output ===\n")
	if aliyunCmd.Stderr != nil {
		if stderr, ok := aliyunCmd.Stderr.(*bytes.Buffer); ok {
			combinedOutput.Write(stderr.Bytes())
		}
	}
	combinedOutput.WriteString("\n=== jq command output ===\n")
	combinedOutput.Write(jqOutput.Bytes())
	combinedOutput.WriteString("\n=== jq command errors ===\n")
	combinedOutput.Write(jqError.Bytes())

	// Write the jq output to the specified file
	if jqOutput.Len() > 0 {
		if err := os.WriteFile(outputFile, jqOutput.Bytes(), 0644); err != nil {
			return combinedOutput.String(), fmt.Errorf("failed to write output file: %w", err)
		}
	}

	// Check if jq command had any errors
	if jqErr != nil {
		return combinedOutput.String(), fmt.Errorf("jq command failed: %w", jqErr)
	}

	return combinedOutput.String(), nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-load-balancer", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		fmt.Printf("Output:\n%s\n", result)
		os.Exit(1)
	}
	fmt.Printf("Success! Output saved to output.json\n")
	fmt.Printf("Command output:\n%s\n", result)
}

