	jqCmd.Stdout = io.MultiWriter(&outputBuffer, outFile)
	jqCmd.Stderr = &outputBuffer

	// Start jq command first since it reads from aliyun's stdout
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		return outputBuffer.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return outputBuffer.String(), fmt.Errorf("jq command failed: %w", err)
	}

	return outputBuffer.String(), nil
}

