import (
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Enhanced input validation
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("parameters cannot be empty")
	}

	// Validate loadBalancerName contains only safe characters
	// Allow alphanumeric, dash, underscore, and period (common in names)
	for _, r := range loadBalancerName {
		if !((r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z') || 
			(r >= '0' && r <= '9') || r == '-' || r == '_' || r == '.') {
			return "", fmt.Errorf("invalid characters in loadBalancerName")
		}
	}

	// Validate outputFile is a safe path
	if strings.Contains(outputFile, "..") || strings.ContainsAny(outputFile, "|>$&;`") {
		return "", fmt.Errorf("invalid characters in outputFile")
	}

	// Create the first command: aliyun slb DescribeLoadBalancers
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", 
		"--LoadBalancerName", loadBalancerName)

	// Create the second command: jq
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe the output of aliyunCmd to jqCmd
	jqCmd.Stdin, _ = aliyunCmd.StdoutPipe()

	// Create output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Set jq's output to the file
	jqCmd.Stdout = outFile

	// Start jq command first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run aliyun command and capture its stderr
	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get stderr pipe: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Read stderr from aliyun command
	stderrBytes, _ := io.ReadAll(aliyunStderr)

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		return string(stderrBytes), fmt.Errorf("aliyun command failed: %w, stderr: %s", 
			err, string(stderrBytes))
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Read the output file content to return
	outputBytes, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(outputBytes), nil
}

