package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to query SLB information
// and exports the formatted result to a JSON file using jq.
// It returns the combined stdout/stderr output and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Build the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers",
		"--LoadBalancerName", loadBalancerName)

	// Build the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun's stdout to jq's stdin
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %v", err)
	}
	jqCmd.Stdin = pipe

	// Create buffers to capture output
	var outputBuffer bytes.Buffer
	var errorBuffer bytes.Buffer

	// Set jq's stdout to our buffer and stderr to error buffer
	jqCmd.Stdout = &outputBuffer
	jqCmd.Stderr = &errorBuffer

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %v", err)
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Process.Kill()
		return "", fmt.Errorf("failed to start jq command: %v", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		jqCmd.Process.Kill()
		return "", fmt.Errorf("aliyun command failed: %v", err)
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %v", err)
	}

	// Write the output to file
	if err := os.WriteFile(outputFile, outputBuffer.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %v", err)
	}

	// Combine stdout and stderr for the return value
	result := strings.TrimSpace(outputBuffer.String())
	if errorBuffer.Len() > 0 {
		result += "\nErrors:\n" + errorBuffer.String()
	}

	return result, nil
}

func main() {
	// Example usage
	loadBalancerName := "my-loadbalancer"
	outputFile := "output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Command executed successfully. Output written to %s\n", outputFile)
	if result != "" {
		fmt.Println("Output:", result)
	}
}

