package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Enhanced input validation
	if strings.ContainsAny(loadBalancerName, "\n\r\t|>;`$&(){}[]'\"\\") {
		return "", fmt.Errorf("invalid characters in loadBalancerName")
	}
	if strings.ContainsAny(outputFile, "\n\r\t|>;`$&(){}[]'\"\\") {
		return "", fmt.Errorf("invalid characters in outputFile")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the first command: aliyun slb DescribeLoadBalancers
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the second command: jq '.LoadBalancers.LoadBalancer[]'
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create pipe between commands
	var err error
	cmd2.Stdin, err = cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	// Create output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Set jq's output to the file
	cmd2.Stdout = outFile

	// Buffer for capturing stderr
	var stderrBuf bytes.Buffer
	cmd2.Stderr = &stderrBuf

	// Start jq command first (it needs the pipe from aliyun)
	if err := cmd2.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run aliyun command and capture its stderr
	aliyunOutput, err := cmd1.CombinedOutput()
	if err != nil {
		return string(aliyunOutput), fmt.Errorf("aliyun command failed: %w, output: %s", err, string(aliyunOutput))
	}

	// Wait for jq command to complete
	if err := cmd2.Wait(); err != nil {
		// Read any stderr from jq
		jqStderr := stderrBuf.String()
		if jqStderr != "" {
			return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr)
		}
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Return success message
	return fmt.Sprintf("Successfully exported SLB data to %s", outputFile), nil
}

