package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Additional security validation
	if strings.Contains(loadBalancerName, "'") || strings.Contains(loadBalancerName, "\"") ||
		strings.Contains(outputFile, "'") || strings.Contains(outputFile, "\"") {
		return "", fmt.Errorf("input parameters cannot contain quotes")
	}

	// Create the output file first to ensure we have write permissions
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	file.Close()

	// Build the aliyun command with proper argument passing
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Build the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe aliyun command output to jq
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	// Open the output file for writing
	output, err := os.OpenFile(outputFile, os.O_WRONLY|os.O_TRUNC, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer output.Close()

	// Set jq's output to the file
	jqCmd.Stdout = output

	// Start jq command first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run aliyun command
	if err := aliyunCmd.Run(); err != nil {
		jqCmd.Process.Kill()
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Read the output file to return its content
	content, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(content), nil
}

// Example usage
func main() {
	result, err := QuerySLBAndExport("my-load-balancer", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Success: %s\n", result)
}

