// QuerySLBAndExport executes the aliyun CLI command to query SLB information
// and exports the formatted result to a JSON file using jq.
// Parameters:
//   - loadBalancerName: Name filter for the SLB query
//   - outputFile: Path where the JSON output will be saved
//
// Returns:
//   - Combined stdout/stderr output as string
//   - Any error encountered during command execution
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate required parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command with the specified load balancer name
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command to format the output
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe aliyun command output to jq command
	jqCmd.Stdin, _ = aliyunCmd.StdoutPipe()

	// Create buffers to capture output and errors
	var outputBuffer bytes.Buffer
	var errorBuffer bytes.Buffer

	// Set jq command's stdout to our buffer and stderr to error buffer
	jqCmd.Stdout = &outputBuffer
	jqCmd.Stderr = &errorBuffer

	// Start the jq command first (it will wait for input from aliyun)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %v", err)
	}

	// Run the aliyun command
	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to run aliyun command: %v", err)
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		// If jq fails, return the error along with any captured output
		return errorBuffer.String(), fmt.Errorf("jq command failed: %v", err)
	}

	// Write the formatted output to the specified file
	if err := os.WriteFile(outputFile, outputBuffer.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %v", err)
	}

	// Return the combined output for verification
	return outputBuffer.String(), nil
}

func main() {
	// Example usage
