			return "", fmt.Errorf("invalid characters in loadBalancerName")
		}
	}

	// Validate outputFile path - prevent directory traversal
	if strings.Contains(outputFile, "..") || strings.Contains(outputFile, "/") || strings.Contains(outputFile, "\\") {
		return "", fmt.Errorf("invalid output file path")
	}

	// Create the output file first to control permissions
	f, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	f.Close()

	// Construct commands without shell injection risk
	// First command: aliyun CLI
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe the output of cmd1 to cmd2
	cmd2.Stdin, err = cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	// Open the output file for writing
	outputFileHandle, err := os.OpenFile(outputFile, os.O_WRONLY|os.O_TRUNC, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer outputFileHandle.Close()

	// Set cmd2's stdout to the file
	cmd2.Stdout = outputFileHandle

	// Start cmd2 first (it needs the pipe from cmd1)
	if err := cmd2.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run cmd1 and capture any error
	if err := cmd1.Run(); err != nil {
		return "", fmt.Errorf("failed to run aliyun command: %w", err)
	}

	// Wait for cmd2 to finish
	if err := cmd2.Wait(); err != nil {
		return "", fmt.Errorf("failed to wait for jq command: %w", err)
	}

	// Read the output file to return its content
	content, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(content), nil
}

