package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Create the output file
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Build the first command: aliyun slb DescribeLoadBalancers
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Build the second command: jq '.LoadBalancers.LoadBalancer[]'
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe between cmd1 stdout and cmd2 stdin
	pipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	cmd2.Stdin = pipe
	cmd2.Stdout = file

	// Buffer to capture stderr from both commands
	var stderrBuf bytes.Buffer
	cmd1.Stderr = &stderrBuf
	cmd2.Stderr = &stderrBuf

	// Start the second command first
	if err := cmd2.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start the first command
	if err := cmd1.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for the first command to complete
	if err := cmd1.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for the second command to complete
	if err := cmd2.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("jq command failed: %w", err)
	}

	// Read the output file content to return
	content, err := os.ReadFile(outputFile)
	if err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to read output file: %w", err)
	}

	return string(content), nil
}

