// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs are not empty if required
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Additional validation for outputFile path safety
	if strings.Contains(outputFile, "..") || strings.ContainsAny(outputFile, "`$|>&;") {
		return "", fmt.Errorf("invalid characters in outputFile")
	}

	// Create the aliyun command with proper argument passing
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe aliyun command output to jq command
	jqCmd.Stdin, _ = aliyunCmd.StdoutPipe()
	jqCmd.Stderr = os.Stderr

	// Create output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Set jq's stdout to the file
	jqCmd.Stdout = outFile

	// Start the jq command first since it will read from aliyun's stdout
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run the aliyun command
	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Since output is redirected to file, we return a success message
	return fmt.Sprintf("SLB data successfully exported to %s", outputFile), nil
