package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// First command: aliyun slb DescribeLoadBalancers
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq '.LoadBalancers.LoadBalancer[]'
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create pipeline: cmd1 stdout -> cmd2 stdin
	var output bytes.Buffer
	cmd2.Stdin, err = cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	// cmd2 stdout goes to both output buffer and file
	multiWriter := io.MultiWriter(&output, outFile)
	cmd2.Stdout = multiWriter
	cmd2.Stderr = &output

	// Start cmd2 first (it needs the pipe)
	if err := cmd2.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start cmd1 and wait for it to complete
	if err := cmd1.Run(); err != nil {
		return "", fmt.Errorf("failed to run aliyun command: %w", err)
	}

	// Wait for cmd2 to complete
	if err := cmd2.Wait(); err != nil {
		// Check if it's exit status 0 (success) or other
		if exitErr, ok := err.(*exec.ExitError); ok {
			if exitErr.ExitCode() != 0 {
				return output.String(), fmt.Errorf("jq command failed with exit code %d: %w", exitErr.ExitCode(), err)
			}
		} else {
			return output.String(), fmt.Errorf("failed to wait for jq command: %w", err)
		}
	}

	return output.String(), nil
}

