import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate output file path to prevent directory traversal
	if outputFile == "" {
		return "", fmt.Errorf("output file path cannot be empty")
	}

	// Clean the output file path to prevent directory traversal attacks
	cleanOutputFile := filepath.Clean(outputFile)
	if cleanOutputFile != outputFile {
		return "", fmt.Errorf("invalid output file path: contains directory traversal")
	}

	// Additional validation: ensure output file is within current directory or allowed paths
	absOutput, err := filepath.Abs(cleanOutputFile)
	if err != nil {
		return "", fmt.Errorf("failed to resolve output file path: %w", err)
	}

	// Optional: restrict to current working directory for security
	cwd, err := os.Getwd()
	if err != nil {
		return "", fmt.Errorf("failed to get current directory: %w", err)
	}

	if !strings.HasPrefix(absOutput, cwd) {
		return "", fmt.Errorf("output file must be within current working directory")
	}

	// Build the command pipeline without shell injection
	// Use exec.Command with separate arguments for each command in the pipeline

	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create the pipeline: aliyunCmd | jqCmd > outputFile
	jqCmd.Stdin, _ = aliyunCmd.StdoutPipe()

	// Create the output file
	outFile, err := os.Create(cleanOutputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	jqCmd.Stdout = outFile

	// Start the jq command first (it will wait for stdin)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run the aliyun command
	aliyunOutput, err := aliyunCmd.CombinedOutput()
	if err != nil {
		jqCmd.Process.Kill()
		return "", fmt.Errorf("aliyun command failed: %w, output: %s", err, string(aliyunOutput))
	}

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Read the output file content to return
	fileContent, err := os.ReadFile(cleanOutputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(fileContent), nil
}

