import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Build the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Build the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create pipe between aliyun and jq
	r, w := io.Pipe()
	aliyunCmd.Stdout = w
	jqCmd.Stdin = r

	// Create buffer to capture jq output
	var jqOutput bytes.Buffer
	jqCmd.Stdout = &jqOutput

	// Start jq command first
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close the write end of the pipe
	w.Close()

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Write output to file
	outputStr := jqOutput.String()
	if outputFile != "" {
		file, err := os.Create(outputFile)
		if err != nil {
			return "", fmt.Errorf("failed to create output file: %w", err)
		}
		defer file.Close()

		if _, err := file.WriteString(outputStr); err != nil {
			return "", fmt.Errorf("failed to write to output file: %w", err)
		}
	}

	return outputStr, nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-load-balancer", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Query completed successfully.\nOutput: %s\n", strings.TrimSpace(result))
}

