	jqCmd := exec.Command(
		"jq",
		".LoadBalancers.LoadBalancer[]",
	)

	// Create a pipe to connect aliyun stdout to jq stdin
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	jqCmd.Stdin = pipe

	// Create buffers to capture combined output
	var outputBuffer bytes.Buffer
	var errorBuffer bytes.Buffer

	// Capture jq stdout and stderr
	jqCmd.Stdout = &outputBuffer
	jqCmd.Stderr = &errorBuffer

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Process.Kill()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for both commands to complete
	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	// Check for errors from either command
	if aliyunErr != nil {
		return errorBuffer.String(), fmt.Errorf("aliyun command failed: %w", aliyunErr)
	}
	if jqErr != nil {
		return errorBuffer.String(), fmt.Errorf("jq command failed: %w", jqErr)
	}

	// Write the formatted output to the specified file
	if err := os.WriteFile(outputFile, outputBuffer.Bytes(), 0644); err != nil {
		return errorBuffer.String(), fmt.Errorf("failed to write output file: %w", err)
	}

	// Return combined output (stdout + stderr)
	combinedOutput := outputBuffer.String() + errorBuffer.String()
	return strings.TrimSpace(combinedOutput), nil
}

func main() {
