	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create pipe between cmd1 stdout and cmd2 stdin
	pipeReader, pipeWriter := io.Pipe()
	cmd1.Stdout = pipeWriter
	cmd2.Stdin = pipeReader

	// Capture cmd2 output
	var outputBuffer bytes.Buffer
	cmd2.Stdout = &outputBuffer

	// Start both commands
